const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 10000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const _SUPABASE_URL = $vars.CARGLASS_SUPABASE_URL;
const _SUPABASE_KEY = $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY;
const _SB_HEADERS = { apikey: _SUPABASE_KEY, Authorization: 'Bearer ' + _SUPABASE_KEY };
async function resolveConvId(input) {
  if (!input) return null;
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(input))) return input;
  try {
    const r1 = await fetch(`${_SUPABASE_URL}/rest/v1/calls?external_call_id=eq.${encodeURIComponent(input)}&select=id&limit=1`, { headers: _SB_HEADERS });
    if (!r1.ok) return null;
    const calls = await r1.json();
    if (!calls.length) return null;
    const r2 = await fetch(`${_SUPABASE_URL}/rest/v1/conversations?call_id=eq.${calls[0].id}&select=id&limit=1`, { headers: _SB_HEADERS });
    if (!r2.ok) return null;
    const cv = await r2.json();
    return cv.length ? cv[0].id : null;
  } catch (e) { return null; }
}

const body = $input.first().json.body || {};
body.conversation_id = await resolveConvId(body.conversation_id);
if (!body.conversation_id) return [{ json: { ok: false, error_code: 'CONVERSATION_NOT_FOUND' } }];
const sb = $vars.CARGLASS_SUPABASE_URL;
const headers = {
  apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY,
  Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY,
  'Prefer': 'resolution=merge-duplicates,return=minimal',
};
if (body.event === 'tool_called') {
  const r = await fetch(`${sb}/rest/v1/tool_calls`, {
    method: 'POST', headers,
    body: {
      id: body.tool_call_id || undefined,
      conversation_id: body.conversation_id,
      tool_name: body.tool_name,
      request_payload: body.request_payload || null,
      status: 'success',
    },
  });
  if (!r.ok) return [{ json: { ok: false, error_code: 'INSERT_FAILED', details: await r.text() } }];
  return [{ json: { ok: true } }];
}
if (body.event === 'tool_result') {
  const status = body.error_message ? 'error' : (body.status || 'success');
  if (body.tool_call_id) {
    const r = await fetch(`${sb}/rest/v1/tool_calls?id=eq.${body.tool_call_id}`, {
      method: 'PATCH', headers,
      body: {
        response_payload: body.response_payload || null,
        status, latency_ms: body.latency_ms || null,
        error_message: body.error_message || null,
      },
    });
    if (!r.ok) return [{ json: { ok: false, error_code: 'PATCH_FAILED', details: await r.text() } }];
  }
  await fetch(`${sb}/rest/v1/integration_health`, {
    method: 'POST', headers,
    body: {
      integration: 'n8n',
      endpoint: '/webhook/' + (body.tool_name || 'unknown'),
      status_code: status === 'success' ? 200 : 500,
      latency_ms: body.latency_ms || 0,
      success: status === 'success',
      conversation_id: body.conversation_id || null,
      error_message: body.error_message || null,
    },
  });
  return [{ json: { ok: true } }];
}
return [{ json: { ok: false, error_code: 'UNKNOWN_EVENT' } }];
